function loadBackupIndex() {
    try {
        return JSON.parse(fs.readFileSync(BACKUP_INDEX_FILE, 'utf-8'));
    } catch (e) {
        return { backups: [], lastBackup: null, lastSessionNumber: 0 };
    }
}

